//! Runie Core ŌĆö State, Events, Update, UI Architecture
//!
//! Architecture (three layers):
//!   model     :: AppState, ChatMessage (source of truth)
//!   event     :: Event enum (all possible state transitions)
//!   update    :: State transitions (pure functions)
//!   ui        :: Elements, Transform (view layer)
//!   labels    :: Static text constants

pub mod model;
pub mod event;
pub mod update;
pub mod labels;
pub mod ui;
pub mod provider;
pub mod session;
pub mod input_history;
pub mod keybindings;
pub mod tokens;
pub mod file_refs;
pub mod fuzzy;
pub mod snapshot;
pub mod config_reload;
#[cfg(test)]
pub mod dsl;

#[cfg(test)]
mod tests;
