}

pub(crate) fn strip_tool_markers(content: &str) -> String {
    if let Some(pos) = content.find("TOOL:") {
        let before = &content[..pos];
        return before.trim_end().to_string();
    }
    let mut result = String::new();
    for line in content.lines() {
        let trimmed = line.trim();
        if trimmed.starts_with('{') {
            if let Ok(val) = serde_json::from_str::<serde_json::Value>(trimmed) {
                if val.get("name").is_some() && val.get("arguments").is_some() {
                    continue;
                }
            }
        }
        if !result.is_empty() {
            result.push('\n');
        }
        result.push_str(line);
    }
    result
}

pub(crate) fn content_has_tool_markers(content: &str) -> bool {
    if content.contains("TOOL:") {
        return true;
    }
    content.lines().any(|line| {
        let trimmed = line.trim();
        if !trimmed.starts_with('{') {
            return false;
        }
        serde_json::from_str::<serde_json::Value>(trimmed)
            .map(|v| v.get("name").is_some() && v.get("arguments").is_some())
            .unwrap_or(false)
    })
}

impl AppState {
    pub fn update(&mut self, event: Event) {
        match event {
            Event::Input(c) => self.push_input(c),
            Event::Backspace => self.pop_input(),
            Event::Newline => self.insert_newline(),
            Event::CursorLeft => self.cursor_left(),
            Event::CursorRight => self.cursor_right(),
            Event::CursorStart => self.cursor_start(),
            Event::CursorEnd => self.cursor_end(),
            Event::DeleteWord => self.delete_word(),
            Event::DeleteToEnd => self.delete_to_end(),
            Event::DeleteToStart => self.delete_to_start(),
            Event::KillChar => self.kill_char(),
            Event::HistoryPrev => {
                if self.input.contains('\n') {
                    self.move_cursor_up();
                } else {
                    self.history_prev();
                }
            }
            Event::HistoryNext => {
                if self.input.contains('\n') {
                    self.move_cursor_down();
                } else {
                    self.history_next();
                }
            }
            Event::Undo => self.undo(),
            Event::Redo => self.redo(),
            Event::CursorWordLeft => self.cursor_word_left(),
            Event::CursorWordRight => self.cursor_word_right(),
            Event::Paste(text) => self.paste(&text),
            Event::Submit => self.submit(),
            Event::ScrollUp => {
                if self.messages.is_empty() && !self.turn_active {
                    self.input_flash = 3;
                }
                self.scroll = self.scroll.saturating_add(1);
            }
            Event::ScrollDown => {
                if self.scroll == 0 {
                    self.input_flash = 3;
                }
                self.scroll = self.scroll.saturating_sub(1);
            }
            Event::Quit => {}
            Event::Reset => *self = AppState::default(),
            Event::AgentThinking { id } => {
                self.set_thinking(id);
                self.ensure_turn_complete_last();
            }
            Event::AgentThoughtDone { id } => {
                self.add_thought(id);
                self.ensure_turn_complete_last();
            }
            Event::AgentToolStart { id, name } => {
                self.start_tool(id, name);
                self.ensure_turn_complete_last();
            }
            Event::AgentToolEnd { duration_secs, output } => {
                self.end_tool(duration_secs, output);
                self.ensure_turn_complete_last();
            }
            Event::AgentResponse { id, content } => {
                self.append_response(id, content);
                self.ensure_turn_complete_last();
            }
            Event::AgentTurnComplete { id, duration_secs } => {
                self.complete_turn(id, duration_secs);
                self.ensure_turn_complete_last();
            }
            Event::AgentDone { id } => self.finish_turn(id),
            Event::AgentError { id, message } => {
                self.add_error(id, message);
                self.ensure_turn_complete_last();
            }
            Event::SwitchModel { provider, model } => self.switch_model(provider, model),
            Event::SwitchTheme { name } => self.switch_theme(name),
            Event::FollowUp => self.queue_follow_up(),
            Event::Abort => self.abort_queue(),
            Event::SpawnAgent => {}
            Event::ToggleExpand => self.toggle_expand_all(),
        }
    }

    fn toggle_expand_all(&mut self) {
        self.all_collapsed = !self.all_collapsed;
        self.messages_changed();
    }

    fn switch_model(&mut self, provider: String, model: String) {
        self.current_provider = provider.clone();
        self.current_model = model.clone();
        self.add_system_msg(format!("Switched to {}/{}", provider, model));
    }

    fn switch_theme(&mut self, name: String) {
        self.theme_name = name.clone();
        self.add_system_msg(format!("Theme switched to '{}'", name));
    }

    pub fn peek_queue(&self) -> Option<&(String, String)> {
        self.request_queue.front()
    }

    pub fn pop_queue(&mut self) -> Option<(String, String)> {
        self.request_queue.pop_front()
    }

    fn add_system_msg(&mut self, content: String) {
        self.messages.push(ChatMessage {
            role: Role::System,
            content,
            timestamp: now(),
            id: "system".to_string(),
        });
        self.messages_changed();
    }

    /// Move TurnComplete to the end of messages and bump its timestamp.
    /// Called after every agent event to ensure TurnComplete remains last.
    fn ensure_turn_complete_last(&mut self) {
        if let Some(idx) = self.messages.iter().position(|m| m.role == Role::TurnComplete) {
            let mut tc = self.messages.remove(idx);
            tc.timestamp = now();
            self.messages.push(tc);
            self.messages_changed();
        }
    }
}

//! Runie Terminal ŌĆö Non-blocking event loop with render actor
//!
//! Architecture (impossible to block by design):
//!   1. Event loop: single-threaded async, only async ops
//!   2. State: owned by event loop, mutable borrow per event
//!   3. Snapshot: immutable frame description (the UI DSL)
//!   4. Render actor: owns Terminal, receives Snapshots via channel
//!   5. If render is slow, old Snapshots are dropped ŌĆö event loop never waits

mod keymap;

use crossterm::event::EventStream;
use futures::StreamExt;
use ratatui::{backend::CrosstermBackend, Terminal};
use runie_agent::{AgentCommand, run_agent_turn};
use runie_core::{AppState, Event as CoreEvent, Snapshot, keybindings, config_reload};
use std::{collections::HashMap, io, time::Duration};
use tokio::sync::mpsc;

const ANIM_MS: u64 = 200;

struct Cleanup;

impl Drop for Cleanup {
    fn drop(&mut self) {
        let _ = crossterm::execute!(std::io::stdout(), crossterm::terminal::LeaveAlternateScreen);
        let _ = crossterm::terminal::disable_raw_mode();
    }
}

#[tokio::main(flavor = "multi_thread", worker_threads = 2)]
async fn main() -> io::Result<()> {
    let _cleanup = Cleanup;
    let terminal = setup_terminal()?;
    let state = AppState::default();

    let (input_tx, input_rx) = mpsc::channel::<CoreEvent>(100);
    let (agent_tx, agent_rx) = mpsc::channel::<CoreEvent>(100);
    let (cmd_tx, cmd_rx) = mpsc::channel::<AgentCommand>(10);
    let (render_tx, render_rx) = mpsc::channel::<Snapshot>(1);

    let keybindings = keybindings::load_keybindings(&None);

    tokio::spawn(agent_loop(cmd_rx, agent_tx));
    tokio::spawn(input_reader(input_tx.clone(), keybindings));
    tokio::spawn(render_task(terminal, render_rx));
    tokio::spawn(config_reload::spawn_config_watcher(input_tx, config_reload::config_path()));

    event_loop(state, input_rx, agent_rx, cmd_tx, render_tx).await
}

fn setup_terminal() -> io::Result<Terminal<CrosstermBackend<std::io::Stdout>>> {
    crossterm::terminal::enable_raw_mode()?;
    crossterm::execute!(
        std::io::stdout(),
        crossterm::terminal::EnterAlternateScreen,
        crossterm::event::EnableBracketedPaste,
    )?;
    Terminal::new(CrosstermBackend::new(std::io::stdout()))
}

async fn render_task(
    mut terminal: Terminal<CrosstermBackend<std::io::Stdout>>,
    mut render_rx: mpsc::Receiver<Snapshot>,
) {
    while let Some(snap) = render_rx.recv().await {
        let _ = terminal.draw(|f| runie_tui::ui::draw_snapshot(f, &snap));
    }
}

async fn input_reader(input_tx: mpsc::Sender<CoreEvent>, bindings: HashMap<String, String>) {
    let mut reader = EventStream::new();
    while let Some(Ok(event)) = reader.next().await {
        if let Some(evt) = keymap::convert_event(&event, &bindings) {
            let is_quit = matches!(&evt, CoreEvent::Quit | CoreEvent::Reset);
            if input_tx.send(evt).await.is_err() { break; }
            if is_quit { break; }
        }
    }
}

async fn event_loop(
    mut state: AppState,
    mut input_rx: mpsc::Receiver<CoreEvent>,
    mut agent_rx: mpsc::Receiver<CoreEvent>,
    cmd_tx: mpsc::Sender<AgentCommand>,
    render_tx: mpsc::Sender<Snapshot>,
) -> io::Result<()> {
    let mut anim = tokio::time::interval(Duration::from_millis(ANIM_MS));

    // Initial draw so the user sees the app immediately, without waiting
    // for the first keyboard event.
    state.ensure_fresh();
    let _ = render_tx.try_send(state.snapshot());

    loop {
        tokio::select! {
            biased;

            Some(evt) = input_rx.recv() => {
                let was_submit = matches!(evt, CoreEvent::Submit);
                let was_followup = matches!(evt, CoreEvent::FollowUp);
                let was_quit = matches!(evt, CoreEvent::Quit | CoreEvent::Reset);
                state.update(evt);
                if was_submit || was_followup {
                    spawn_if_queued(&mut state, &cmd_tx).await;
                }
                if was_quit {
                    return Ok(());
                }
            }

            Some(evt) = agent_rx.recv() => {
                let was_done = matches!(evt, CoreEvent::AgentDone { .. } | CoreEvent::AgentError { .. });
                state.update(evt);
                if was_done {
                    spawn_if_queued(&mut state, &cmd_tx).await;
                }
            }

            _ = anim.tick() => {
                state.tick_animation();
            }
        }

        state.ensure_fresh();
        let snap = state.snapshot();
        if render_tx.try_send(snap).is_err() {
            // Render task is behind ŌĆö old snapshot dropped, latest will draw
        }
    }
}

async fn agent_loop(mut cmd_rx: mpsc::Receiver<AgentCommand>, agent_tx: mpsc::Sender<CoreEvent>) {
    while let Some(cmd) = cmd_rx.recv().await {
        let agent_tx_clone = agent_tx.clone();
        let cmd_id = cmd.id.clone();

        let result = run_agent_turn(
            &cmd,
            |evt| {
                let tx = agent_tx_clone.clone();
                let _ = tx.try_send(evt);
            },
            5,
        ).await;

        if let Err(e) = result {
            let _ = agent_tx.send(CoreEvent::AgentError {
                id: cmd_id,
                message: format!("Agent error: {}", e),
            }).await;
        }
    }
}

async fn spawn_if_queued(state: &mut AppState, cmd_tx: &mpsc::Sender<AgentCommand>) {
    if let Some((content, id)) = state.peek_queue() {
        let content = content.clone();
        let id = id.clone();
        state.pop_queue();
        state.streaming = true;
        state.turn_active = true;
        state.inflight += 1;
        let _ = cmd_tx.send(AgentCommand {
            content,
            id,
            provider: state.current_provider.clone(),
            model: state.current_model.clone(),
        }).await;
    }
}

#[cfg(test)]
mod tests {
    use crossterm::event::KeyCode;

    #[test]
    fn animation_interval_is_200ms() {
        assert_eq!(super::ANIM_MS, 200, "ANIM_MS must be 200ms for visible braille spinner, got {}", super::ANIM_MS);
    }

    #[tokio::test]
    async fn spawn_if_queued_sets_turn_active_and_inflight() {
        let (tx, mut rx) = tokio::sync::mpsc::channel::<super::AgentCommand>(10);
        let mut state = super::AppState::default();
        state.request_queue.push_back(("hello".to_string(), "req.0".to_string()));

        assert!(!state.turn_active);
        assert_eq!(state.inflight, 0);

        super::spawn_if_queued(&mut state, &tx).await;

        assert!(state.turn_active, "spawn_if_queued must set turn_active");
        assert_eq!(state.inflight, 1, "spawn_if_queued must increment inflight");
        assert!(state.request_queue.is_empty(), "Message should be popped from request_queue");

        let cmd = rx.try_recv().expect("Command should be sent to agent");
        assert_eq!(cmd.content, "hello");
    }

    #[tokio::test]
    async fn spawn_if_queued_noop_when_queue_empty() {
        let (tx, _rx) = tokio::sync::mpsc::channel::<super::AgentCommand>(10);
        let mut state = super::AppState::default();

        super::spawn_if_queued(&mut state, &tx).await;

        assert!(!state.turn_active);
        assert_eq!(state.inflight, 0);
    }
}

use unicode_segmentation::UnicodeSegmentation;
use super::*;

// === Grapheme helpers ===

fn prev_grapheme_boundary(s: &str, pos: usize) -> usize {
    let mut last = 0;
    for (i, _) in s.grapheme_indices(true) {
        if i >= pos { break; }
        last = i;
    }
    last
}

fn next_grapheme_boundary(s: &str, pos: usize) -> usize {
    for (i, _) in s.grapheme_indices(true) {
        if i > pos { return i; }
    }
    s.len()
}

// === Word boundary helpers ===

fn find_word_boundary_left(s: &str, pos: usize) -> usize {
    let mut pos = pos;
    while pos > 0 {
        let prev = prev_grapheme_boundary(s, pos);
        if &s[prev..pos] != " " { break; }
        pos = prev;
    }
    while pos > 0 {
        let prev = prev_grapheme_boundary(s, pos);
        if &s[prev..pos] == " " { break; }
        pos = prev;
    }
    pos
}

fn find_word_boundary_right(s: &str, pos: usize) -> usize {
    let mut pos = pos;
    let len = s.len();
    while pos < len {
        let next = next_grapheme_boundary(s, pos);
        if &s[pos..next] == " " { break; }
        pos = next;
    }
    while pos < len {
        let next = next_grapheme_boundary(s, pos);
        if &s[pos..next] != " " { break; }
        pos = next;
    }
    pos
}

impl AppState {
    pub fn hint_text(&self) -> String {
        let mut parts = Vec::new();
        parts.push("Ctrl+Shift+E=expand/collapse".to_string());
        if self.at_suggestions.is_some() {
            parts.push("Tab=cycle".to_string());
            parts.push("Enter=insert".to_string());
            parts.push("Esc=close".to_string());
        } else if self.turn_active {
            parts.push("Enter=steer".to_string());
            parts.push("Alt+Enter=follow-up".to_string());
            parts.push("Esc=abort".to_string());
        } else if !self.input.is_empty() {
            parts.push("Enter=send".to_string());
            parts.push("Alt+Enter=follow-up".to_string());
            parts.push("Esc=clear".to_string());
        } else {
            parts.push("Alt+Enter=follow-up".to_string());
            parts.push("Esc=clear".to_string());
        }
        parts.push("Ctrl+C=quit".to_string());
        parts.join(" | ")
    }

    // === Cursor Movement (grapheme-aware) ===

    pub(crate) fn cursor_left(&mut self) {
        if self.cursor_pos > 0 {
            self.cursor_pos = prev_grapheme_boundary(&self.input, self.cursor_pos);
            self.mark_dirty();
        } else {
            self.input_flash = 3;
        }
    }

    pub(crate) fn cursor_right(&mut self) {
        if self.cursor_pos < self.input.len() {
            self.cursor_pos = next_grapheme_boundary(&self.input, self.cursor_pos);
            self.mark_dirty();
        } else {
            self.input_flash = 3;
        }
    }

    pub(crate) fn cursor_start(&mut self) {
        if self.input.contains('\n') {
            self.move_cursor_to_line_start();
        } else if self.cursor_pos != 0 {
            self.cursor_pos = 0;
            self.mark_dirty();
        } else {
            self.input_flash = 3;
        }
    }

    pub(crate) fn cursor_end(&mut self) {
        if self.input.contains('\n') {
            self.move_cursor_to_line_end();
        } else if self.cursor_pos != self.input.len() {
            self.cursor_pos = self.input.len();
            self.mark_dirty();
        } else {
            self.input_flash = 3;
        }
    }

    // === Word Navigation ===

    pub(crate) fn cursor_word_left(&mut self) {
        if self.cursor_pos > 0 {
            self.cursor_pos = find_word_boundary_left(&self.input, self.cursor_pos);
            self.mark_dirty();
        } else {
            self.input_flash = 3;
        }
    }

    pub(crate) fn cursor_word_right(&mut self) {
        if self.cursor_pos < self.input.len() {
            self.cursor_pos = find_word_boundary_right(&self.input, self.cursor_pos);
            self.mark_dirty();
        } else {
            self.input_flash = 3;
        }
    }

    // === Text Editing ===

    pub(crate) fn insert_char(&mut self, c: char) {
        self.push_undo();
        if self.cursor_pos == self.input.len() {
            self.input.push(c);
        } else {
            self.input.insert(self.cursor_pos, c);
        }
        self.cursor_pos += c.len_utf8();
        self.clear_redo();
        self.handle_at_trigger();
        self.mark_dirty();
    }

    pub(crate) fn delete_before_cursor(&mut self) {
        if self.cursor_pos > 0 {
            // Check if the character before cursor is a newline
            let char_before_cursor = self.input[..self.cursor_pos].chars().last();
            if char_before_cursor == Some('\n') {
                // Remove the newline character (join lines)
                self.push_undo();
                let new_pos = self.cursor_pos - 1; // Position after removing newline
                self.input.remove(self.cursor_pos - 1);
                self.cursor_pos = new_pos;
                self.clear_redo();
                self.handle_at_trigger();
                self.mark_dirty();
            } else {
                // Normal delete - remove grapheme before cursor
                self.push_undo();
                let new_pos = prev_grapheme_boundary(&self.input, self.cursor_pos);
                self.input.drain(new_pos..self.cursor_pos);
                self.cursor_pos = new_pos;
                self.clear_redo();
                self.handle_at_trigger();
                self.mark_dirty();
            }
        } else if self.cursor_pos == 0 && !self.input.is_empty() {
            // Cursor at absolute start - check if there's a newline
            if self.input.starts_with('\n') {
                self.push_undo();
                self.input.remove(0);
                self.clear_redo();
                self.handle_at_trigger();
                self.mark_dirty();
            } else {
                self.input_flash = 3;
            }
        } else {
            self.input_flash = 3;
        }
    }

    pub(crate) fn delete_word(&mut self) {
        if self.cursor_pos == 0 {
            self.input_flash = 3;
            return;
        }
        self.push_undo();
        let start = find_word_boundary_left(&self.input, self.cursor_pos);
        self.input.drain(start..self.cursor_pos);
        self.cursor_pos = start;
        self.clear_redo();
        self.handle_at_trigger();
        self.mark_dirty();
    }

    pub(crate) fn delete_to_end(&mut self) {
        if self.cursor_pos < self.input.len() {
            self.push_undo();
            self.input.truncate(self.cursor_pos);
            self.clear_redo();
            self.handle_at_trigger();
            self.mark_dirty();
        } else {
            self.input_flash = 3;
        }
    }

    pub(crate) fn delete_to_start(&mut self) {
        if self.cursor_pos > 0 {
            self.push_undo();
            self.input.drain(..self.cursor_pos);
            self.cursor_pos = 0;
            self.clear_redo();
            self.handle_at_trigger();
            self.mark_dirty();
        } else {
            self.input_flash = 3;
        }
    }

    pub(crate) fn kill_char(&mut self) {
        if self.cursor_pos < self.input.len() {
            self.push_undo();
            let end = next_grapheme_boundary(&self.input, self.cursor_pos);
            self.input.drain(self.cursor_pos..end);
            self.clear_redo();
            self.handle_at_trigger();
            self.mark_dirty();
        } else {
            self.input_flash = 3;
        }
    }

    // === Undo / Redo ===

    fn push_undo(&mut self) {
        self.undo_stack.push((self.input.clone(), self.cursor_pos));
    }

    fn clear_redo(&mut self) {
        self.redo_stack.clear();
    }

    pub(crate) fn undo(&mut self) {
        if let Some((text, pos)) = self.undo_stack.pop() {
            self.redo_stack.push((self.input.clone(), self.cursor_pos));
            self.input = text;
            self.cursor_pos = pos;
            self.handle_at_trigger();
            self.mark_dirty();
        }
    }

    pub(crate) fn redo(&mut self) {
        if let Some((text, pos)) = self.redo_stack.pop() {
            self.undo_stack.push((self.input.clone(), self.cursor_pos));
            self.input = text;
            self.cursor_pos = pos;
            self.handle_at_trigger();
            self.mark_dirty();
        }
    }

    // === Paste ===

    pub(crate) fn paste(&mut self, text: &str) {
        let clean = text
            .replace("\r\n", "")
            .replace(['\r', '\n'], "")
            .replace('\t', "    ");
        if clean.is_empty() {
            return;
        }
        self.push_undo();
        self.input.insert_str(self.cursor_pos, &clean);
        self.cursor_pos += clean.len();
        self.clear_redo();
        self.handle_at_trigger();
        self.mark_dirty();
    }

    // === Legacy methods ===

    pub(crate) fn push_input(&mut self, c: char) {
        if c == '\t' {
            if self.input.contains('@') || self.at_suggestions.is_some() {
                self.cycle_at_suggestions();
            }
            return;
        }
        self.insert_char(c);
    }

    pub(crate) fn pop_input(&mut self) {
        self.delete_before_cursor();
    }

    pub(crate) fn insert_newline(&mut self) {
        self.push_undo();
        if self.cursor_pos == self.input.len() {
            self.input.push('\n');
        } else {
            self.input.insert(self.cursor_pos, '\n');
        }
        self.cursor_pos += 1;
        self.clear_redo();
        self.mark_dirty();
    }

    pub(crate) fn submit(&mut self) {
        if self.at_suggestions.is_some() {
            self.insert_at_suggestion();
            return;
        }
        if self.input.is_empty() {
            self.input_flash = 3;
            return;
        }
        let content = std::mem::take(&mut self.input).trim().to_string();
        self.cursor_pos = 0;
        self.history_pos = None;
        self.undo_stack.clear();
        self.redo_stack.clear();
        if content.is_empty() {
            return;
        }

        // Handle bash prefix (!)
        if let Some(stripped) = content.strip_prefix('!') {
            let command = stripped.trim().to_string();
            if !command.is_empty() {
                self.run_bash_command(&command);
            }
            return;
        }

        // Add to history and persist
        self.add_to_input_history(content.clone());
        if let Some(response) = self.handle_slash(&content) {
            self.add_system_msg(response);
            return;
        }
        if self.turn_active {
            self.message_queue.push(crate::model::QueuedMessage {
                content,
                kind: crate::model::QueuedMessageKind::Steering,
            });
            self.scroll = 0;
            self.mark_dirty();
            return;
        }
        let id = self.next_id();
        self.messages.push(ChatMessage {
            role: Role::User,
            content: content.clone(),
            timestamp: now(),
            id: id.clone(),
        });
        self.request_queue.push_back((content, id));
        self.scroll = 0;
        self.messages_changed();
    }

    /// Run a bash command and display output
    fn run_bash_command(&mut self, command: &str) {
        let result = bash::execute_bash(command);
        let output_msg = format!("$ {}\n{}", command, result);
        self.add_system_msg(output_msg);
        self.scroll = 0;
        self.messages_changed();
    }

    // === Input History ===

    pub(crate) fn history_prev(&mut self) {
        if self.input_history.is_empty() {
            self.input_flash = 3;
            return;
        }
        let pos = match self.history_pos {
            Some(p) if p > 0 => p - 1,
            Some(p) => p,
            None => self.input_history.len() - 1,
        };
        self.history_pos = Some(pos);
        self.input = self.input_history[pos].clone();
        self.cursor_pos = self.input.len();
        self.mark_dirty();
    }

    pub(crate) fn history_next(&mut self) {
        let pos = match self.history_pos {
            Some(p) => p + 1,
            None => {
                self.input_flash = 3;
                return;
            }
        };
        if pos >= self.input_history.len() {
            self.history_pos = None;
            self.input.clear();
            self.cursor_pos = 0;
        } else {
            self.history_pos = Some(pos);
            self.input = self.input_history[pos].clone();
            self.cursor_pos = self.input.len();
        }
        self.mark_dirty();
    }

    // === @-ref suggestions ===

    fn handle_at_trigger(&mut self) {
        if self.input.contains('@') {
            let query = self.input.split('@').next_back().unwrap_or("").to_string();
            let needs_refresh = self.last_at_query.as_ref() != Some(&query)
                || self.at_suggestions.is_none();
            if needs_refresh {
                self.last_at_query = Some(query.clone());
                self.refresh_at_suggestions();
            }
        } else {
            self.at_suggestions = None;
            self.at_selected = None;
            self.last_at_query = None;
        }
    }

    fn refresh_at_suggestions(&mut self) {
        let query = self.input.split('@').next_back().unwrap_or("").to_string();
        let mut suggestions = crate::file_refs::complete_at_ref(&self.input, ".", 50);
        if suggestions.len() > 1 && !query.is_empty() {
            let refs: Vec<&str> = suggestions.iter().map(|s| s.as_str()).collect();
            suggestions = crate::fuzzy::fuzzy_filter(&query, &refs, 10)
                .into_iter()
                .map(|s| s.to_string())
                .collect();
        }
        if suggestions.is_empty() {
            suggestions = crate::file_refs::find_files("", ".", 10);
        }
        if suggestions.is_empty() {
            self.at_suggestions = None;
            self.at_selected = None;
            return;
        }
        self.at_suggestions = Some(suggestions);
        self.at_selected = Some(0);
        self.mark_dirty();
    }

    fn cycle_at_suggestions(&mut self) {
        if let Some(suggestions) = self.at_suggestions.as_mut() {
            let idx = self.at_selected.map(|i| (i + 1) % suggestions.len()).unwrap_or(0);
            self.at_selected = Some(idx);
            self.mark_dirty();
        } else {
            self.refresh_at_suggestions();
        }
    }

    fn insert_at_suggestion(&mut self) {
        if let Some(idx) = self.at_selected {
            if let Some(suggestions) = self.at_suggestions.take() {
                if let Some(selected) = suggestions.get(idx) {
                    self.input = crate::file_refs::insert_at_ref(&self.input, selected);
                    self.cursor_pos = self.input.len();
                }
            }
            self.at_selected = None;
            self.last_at_query = None;
            self.mark_dirty();
        }
    }
}

//! Session persistence ŌĆö JSON files in ~/.runie/sessions/

use crate::model::ChatMessage;
use serde::{Deserialize, Serialize};
use std::path::PathBuf;

/// Session snapshot ŌĆö serializable conversation state
#[derive(Serialize, Deserialize, Debug, Clone)]
pub struct Session {
    pub name: String,
    pub created_at: f64,
    pub updated_at: f64,
    pub messages: Vec<ChatMessage>,
    pub provider: String,
    pub model: String,
    pub theme_name: String,
}

/// Session store ŌĆö handles save/load/list/delete
#[derive(Debug, Clone)]
pub struct Store {
    pub dir: PathBuf,
}

impl Store {
    /// Default store ŌĆö uses OS data dir (~/.local/share/runie/sessions on Linux)
    pub fn default_store() -> Option<Self> {
        dirs::data_dir().map(|d| Self::new(d.join("runie").join("sessions")))
    }

    /// Store with explicit directory (for testing)
    pub fn new(dir: PathBuf) -> Self {
        Self { dir }
    }

    pub fn path(&self, name: &str) -> PathBuf {
        self.dir.join(format!("{}.json", name))
    }

    fn ensure_dir(&self) -> std::io::Result<()> {
        std::fs::create_dir_all(&self.dir)
    }

    /// Save session to JSON file
    pub fn save(&self, name: &str, session: &Session) -> anyhow::Result<()> {
        self.ensure_dir()?;
        let json = serde_json::to_string_pretty(session)?;
        std::fs::write(self.path(name), json)?;
        Ok(())
    }

    /// Load session from JSON file
    pub fn load(&self, name: &str) -> anyhow::Result<Session> {
        let json = std::fs::read_to_string(self.path(name))?;
        let session: Session = serde_json::from_str(&json)?;
        Ok(session)
    }

    /// List all saved session names (sorted)
    pub fn list(&self) -> anyhow::Result<Vec<String>> {
        if !self.dir.exists() {
            return Ok(Vec::new());
        }
        let mut names = Vec::new();
        for entry in std::fs::read_dir(&self.dir)? {
            let entry = entry?;
            let name = entry.file_name().to_string_lossy().to_string();
            if let Some(stem) = name.strip_suffix(".json") {
                names.push(stem.to_string());
            }
        }
        names.sort();
        Ok(names)
    }

    /// Delete a session file
    pub fn delete(&self, name: &str) -> anyhow::Result<()> {
        std::fs::remove_file(self.path(name))?;
        Ok(())
    }
}



pub fn default_store() -> Option<Store> {
    if let Ok(dir) = std::env::var("RUNIE_SESSIONS_DIR") {
        return Some(Store::new(PathBuf::from(dir)));
    }
    Store::default_store()
}

pub fn save(name: &str, session: &Session) -> anyhow::Result<()> {
    default_store()
        .ok_or_else(|| anyhow::anyhow!("No data directory"))?
        .save(name, session)
}

pub fn load(name: &str) -> anyhow::Result<Session> {
    default_store()
        .ok_or_else(|| anyhow::anyhow!("No data directory"))?
        .load(name)
}

pub fn list() -> anyhow::Result<Vec<String>> {
    default_store()
        .ok_or_else(|| anyhow::anyhow!("No data directory"))?
        .list()
}

pub fn delete(name: &str) -> anyhow::Result<()> {
    default_store()
        .ok_or_else(|| anyhow::anyhow!("No data directory"))?
        .delete(name)
}





